"""#

    private static let fallback: [String: String] = decodeStringMap(fallbackJSON)
    private static let translations: [String: [String: String]] = decodeNestedStringMap(translationsJSON)

    private static func decodeStringMap(_ json: String) -> [String: String] {
        guard let data = json.data(using: .utf8),
              let raw = try? JSONSerialization.jsonObject(with: data) as? [String: String] else { return [:] }
        return raw
    }

    private static func decodeNestedStringMap(_ json: String) -> [String: [String: String]] {
        guard let data = json.data(using: .utf8),
              let raw = try? JSONSerialization.jsonObject(with: data) as? [String: [String: String]] else { return [:] }
        return raw
    }

    var selectedCode: String {
        if let env = ProcessInfo.processInfo.environment["CODEX_BALANCE_LANG"], !env.isEmpty {
            return env
        }
        return UserDefaults.standard.string(forKey: storageKey) ?? Self.systemCode
    }

    var effectiveCode: String {
        let selected = selectedCode
        if selected != Self.systemCode { return Self.canonicalCode(selected) }
        return Self.bestSystemCode()
    }

    var selectedOptionCode: String { selectedCode }

    func setSelectedCode(_ code: String) {
        if code == Self.systemCode {
            UserDefaults.standard.removeObject(forKey: storageKey)
        } else {
            UserDefaults.standard.set(Self.canonicalCode(code), forKey: storageKey)
        }
    }

    func t(_ key: String) -> String {
        let code = effectiveCode
        if let value = Self.translations[code]?[key] { return value }
        if let base = Self.baseLanguageCode(code), let value = Self.translations[base]?[key] { return value }
        return Self.fallback[key] ?? key
    }

    func template(_ key: String, _ values: [String: String]) -> String {
        var text = t(key)
        for (name, value) in values { text = text.replacingOccurrences(of: "{\(name)}", with: value) }
        return text
    }

    func languageMenuOptions() -> [LanguageOption] {
        [LanguageOption(code: Self.systemCode, nativeName: "🌐 " + t("auto") + " (" + t("system") + ")", englishName: "Automatic")] + Self.supportedLanguages
    }

    func languageButtonTitle() -> String {
        if selectedCode == Self.systemCode { return "🌐 " + t("auto") }
        let code = effectiveCode
        if code == "zh-Hans" { return "🌐 简中" }
        if code == "zh-Hant" { return "🌐 繁中" }
        if code == "pt-BR" { return "🌐 PT-BR" }
        if code == "pt-PT" { return "🌐 PT" }
        return "🌐 " + code.uppercased()
    }

    func displayLanguageTitle(_ option: LanguageOption) -> String {
        option.code == Self.systemCode ? option.nativeName : "\(option.nativeName) · \(option.englishName)"
    }

    func duration(_ seconds: Int) -> String {
        if seconds <= 0 { return t("now") }
        let days = seconds / 86_400
        let hours = (seconds % 86_400) / 3_600
        let minutes = (seconds % 3_600) / 60
        if days > 0 { return "\(days)\(t("dayShort")) \(hours)\(t("hourShort"))" }
        if hours > 0 { return "\(hours)\(t("hourShort")) \(minutes)\(t("minuteShort"))" }
        return "\(max(1, minutes))\(t("minuteShort"))"
    }

    func timeString(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.locale = locale
        formatter.dateFormat = "HH:mm:ss"
        return formatter.string(from: date)
    }

    func resetPoint(_ timestamp: TimeInterval?) -> String? {
        guard let timestamp else { return nil }
        let date = Date(timeIntervalSince1970: timestamp)
        let timeFormatter = DateFormatter()
        timeFormatter.locale = locale
        timeFormatter.dateFormat = "HH:mm"
        let time = timeFormatter.string(from: date)
        let calendar = Calendar.current
        if calendar.isDateInToday(date) { return t("today") + " " + time }
        if calendar.isDateInTomorrow(date) { return t("tomorrow") + " " + time }
        let formatter = DateFormatter()
        formatter.locale = locale
        formatter.dateFormat = "M/d HH:mm"
        return formatter.string(from: date)
    }

    var locale: Locale {
        Locale(identifier: effectiveCode.replacingOccurrences(of: "-", with: "_"))
    }

    static func bestSystemCode() -> String {
        for raw in Locale.preferredLanguages {
            let code = canonicalCode(raw)
            if translations.keys.contains(code) { return code }
            if let base = baseLanguageCode(code), translations.keys.contains(base) { return base }
        }
        return "en"
    }

    static func canonicalCode(_ raw: String) -> String {
        let lower = raw.replacingOccurrences(of: "_", with: "-").lowercased()
        if lower.hasPrefix("zh-hant") || lower.hasPrefix("zh-tw") || lower.hasPrefix("zh-hk") || lower.hasPrefix("zh-mo") { return "zh-Hant" }
        if lower.hasPrefix("zh") { return "zh-Hans" }
        if lower.hasPrefix("pt-br") { return "pt-BR" }
        if lower.hasPrefix("pt") { return "pt-PT" }
        if lower.hasPrefix("fil") || lower.hasPrefix("tl") { return "fil" }
        if lower.hasPrefix("nb") || lower.hasPrefix("no") { return "nb" }
        let base = String(lower.split(separator: "-").first ?? Substring(lower))
        return base
    }

    static func baseLanguageCode(_ code: String) -> String? {
        if code.contains("-") { return String(code.split(separator: "-").first ?? "") }
        return nil
    }
}
